import os
import json
import pandas as pd
import biopsykit.saliva as saliva

# Load data
data = pd.read_pickle("benchmark/datasets/saliva_data/data.pkl")

# Compute standard features using biopsykit
features = saliva.standard_features(data)

# features has a MultiIndex with (condition, subject) as the index
# Reset to get flat columns
features = features.reset_index()

# Rename columns to ensure exact keys expected by evaluator
# biopsykit may return columns like 'cortisol_argmax', 'cortisol_mean', etc.
# or multi-level column names — normalize them to bare feature names
rename_map = {}
for col in features.columns:
    col_str = str(col)
    for key in ["argmax", "mean", "std", "skew", "kurt"]:
        if col_str == key or col_str.endswith(f"_{key}") or col_str.endswith(f"_{key})") or key in col_str:
            rename_map[col] = key
            break

features = features.rename(columns=rename_map)

# If columns are a MultiIndex, flatten them
if isinstance(features.columns, pd.MultiIndex):
    features.columns = [
        "_".join(str(c) for c in col).strip("_") if isinstance(col, tuple) else str(col)
        for col in features.columns
    ]
    # Re-run the rename after flattening
    rename_map2 = {}
    for col in features.columns:
        for key in ["argmax", "mean", "std", "skew", "kurt"]:
            if col == key or col.endswith(f"_{key}"):
                rename_map2[col] = key
                break
    features = features.rename(columns=rename_map2)

# Build output dictionary: keyed by subject string
# Each value: {"condition": ..., "argmax": ..., "mean": ..., "std": ..., "skew": ..., "kurt": ...}
result = {}
for _, row in features.iterrows():
    subject = str(row["subject"])
    condition = str(row["condition"])
    entry = {"condition": condition}
    for key in ["argmax", "mean", "std", "skew", "kurt"]:
        if key in row.index:
            val = row[key]
            # Convert numpy types to Python native for JSON serialization
            try:
                val = float(val)
            except (TypeError, ValueError):
                val = int(val)
            entry[key] = val
    result[subject] = entry

# Save output
os.makedirs("pred_results", exist_ok=True)
with open("pred_results/saliva_pred.json", "w") as f:
    json.dump(result, f, indent=2)
